svg.script:
//
(function() {
  var svg    = document.getElementById('root');
  var isDark  = false;
  var isPrint = false;
  var ns      = 'http://www.w3.org/2000/svg';
  var R       = 210;
  var PUSH    = 14;
  /* Pie center in viewBox coords */
  var PCX     = 340;
  var PCY     = 340;

  var sliceSwaps = [
    ['sl1','s1','s1d'], ['sl2','s2','s2d'], ['sl3','s3','s3d'],
    ['sl4','s4','s4d'], ['sl5','s5','s5d'], ['sl6','s6','s6d'],
    ['sl7','soth','sothd']
  ];
  function applyDarkSlices(dark) {
    sliceSwaps.forEach(function(s) {
      var g = document.getElementById(s[0]);
      if (!g) return;
      var path = g.querySelector('.slice-glow');
      if (path) path.setAttribute('fill', 'url(#' + (dark ? s[2] : s[1]) + ')');
    });
  }

  document.getElementById('dark-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (svg.classList.toggle('dark')) { isDark = true;  thumb.setAttribute('cx','52'); lbl.textContent='Light'; }
    else                              { isDark = false; thumb.setAttribute('cx','16'); lbl.textContent='Dark';  }
    applyDarkSlices(isDark);
  });
  document.getElementById('print-toggle').addEventListener('click', function() {
    isPrint = !isPrint;
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (isPrint) { svg.classList.add('print');    thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else         { svg.classList.remove('print'); thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  var tipLayer = document.getElementById('tip-layer');
  var tipMap   = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  svg.querySelectorAll('.slice-g').forEach(function(g) {
    var sliceId = g.id;
    var midDeg  = parseFloat(g.getAttribute('data-mid'));
    var label   = g.getAttribute('data-label');
    var val     = g.getAttribute('data-val');
    var pct     = g.getAttribute('data-pct');

    var midRad = midDeg * Math.PI / 180;
    var dx = Math.cos(midRad);
    var dy = Math.sin(midRad);

    var bw = Math.max(90, label.length * 7 + 30);
    var bh = 56;
    var hw = bw / 2;
    var hh = bh / 2;
    var TAIL = 14;

    var tipX = PCX + dx * R;
    var tipY = PCY + dy * R;
    var bCx  = tipX;
    var bCy  = tipY - hh - TAIL;
    var baseY = bCy + hh;

    var tipG = document.createElementNS(ns, 'g');
    tipG.setAttribute('class', 'tip');
    tipG.setAttribute('data-for', sliceId);
    tipLayer.appendChild(tipG);
    tipMap[sliceId] = tipG;

    tipG.appendChild(el('rect', { x:(bCx-hw).toFixed(1), y:(bCy-hh).toFixed(1),
      width:bw, height:bh, rx:9, 'class':'bub-bg',
      filter:'drop-shadow(0 3px 8px rgba(0,0,0,0.20))' }));
    tipG.appendChild(el('rect', { x:(bCx-hw).toFixed(1), y:(bCy-hh).toFixed(1),
      width:bw, height:bh, rx:9, 'class':'bub-bdr' }));

    tipG.appendChild(el('polygon', {
      points: (bCx-10)+','+(baseY-1)+' '+(bCx+10)+','+(baseY-1)+' '+bCx+','+tipY,
      'class':'bub-tip-poly' }));
    tipG.appendChild(el('path', {
      d: 'M'+(bCx-10)+','+(baseY-1)+' '+bCx+','+tipY+' '+(bCx+10)+','+(baseY-1),
      'class':'bub-bdr', fill:'none', 'stroke-width':'1' }));

    var tv = el('text', { x:bCx.toFixed(1), y:(bCy-10).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central',
      'class':'bub-val' });
    tv.textContent = val; tipG.appendChild(tv);
    var tl = el('text', { x:bCx.toFixed(1), y:(bCy+5).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central',
      'class':'bub-lbl' });
    tl.textContent = label; tipG.appendChild(tl);
    var tp = el('text', { x:bCx.toFixed(1), y:(bCy+18).toFixed(1),
      'text-anchor':'middle', 'dominant-baseline':'central',
      'class':'bub-pct' });
    tp.textContent = pct; tipG.appendChild(tp);

    var pushTx = 'translate(' + (dx*PUSH).toFixed(1) + ',' + (dy*PUSH).toFixed(1) + ')';
    var pushX  = dx * PUSH;
    var pushY  = dy * PUSH;

    g.addEventListener('mouseenter', function() {
      g.querySelectorAll('path').forEach(function(p){ p.setAttribute('transform', pushTx); });
      g.style.filter = 'url(#shadow-hover)';
      tipMap[sliceId].style.opacity = '1';
      tipMap[sliceId].setAttribute('transform',
        'translate(' + pushX.toFixed(1) + ',' + pushY.toFixed(1) + ')');
    });
    g.addEventListener('mouseleave', function() {
      g.querySelectorAll('path').forEach(function(p){ p.removeAttribute('transform'); });
      g.style.filter = '';
      tipMap[sliceId].style.opacity = '';
      tipMap[sliceId].removeAttribute('transform');
    });
  });

  /* ── URL param: ?theme=dark|light sets initial mode ── */
  (function() {
    var params = new URLSearchParams(window.location.search);
    if (params.get('theme') === 'dark') {
      svg.classList.add('dark');
      var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
      applyDarkSlices(true);
    }
  })();

})();
//
